import{_ as p,c as e}from"./app.0b00aae6.js";const r={},t=e('<h1 id="_33-\u8BB2-\u65E0\u5B9E\u4F8B\u65E0\u771F\u76F8-\u57FA\u4E8E-loadrunner-\u5B9E\u73B0\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5B9E\u8DF5-\u4E0B" tabindex="-1"><a class="header-anchor" href="#_33-\u8BB2-\u65E0\u5B9E\u4F8B\u65E0\u771F\u76F8-\u57FA\u4E8E-loadrunner-\u5B9E\u73B0\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5B9E\u8DF5-\u4E0B" aria-hidden="true">#</a> 33 \u8BB2\uFF1A\u65E0\u5B9E\u4F8B\u65E0\u771F\u76F8\uFF1A\u57FA\u4E8E LoadRunner \u5B9E\u73B0\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5B9E\u8DF5\uFF08\u4E0B\uFF09</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\u3002\u4ECA\u5929\u6211\u548C\u4F60\u5206\u4EAB\u7684\u4E3B\u9898\u662F\uFF1A\u65E0\u5B9E\u4F8B\u65E0\u771F\u76F8\u4E4B\u57FA\u4E8E LoadRunner \u5B9E\u73B0\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5B9E\u8DF5\uFF08\u4E0B\uFF09\u3002</p><p>\u4ECA\u5929\uFF0C\u6211\u4F1A\u7EE7\u7EED\u548C\u4F60\u5206\u4EAB\u5982\u4F55\u57FA\u4E8E LoadRunner \u5B8C\u6210\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u7684\u6027\u80FD\u6D4B\u8BD5\u3002\u901A\u8FC7\u6211\u4E0A\u4E00\u6B21\u7684\u5206\u4EAB\uFF0C\u4F60\u5DF2\u7ECF\u6E05\u695A\u77E5\u9053\u4E86\uFF0C\u6574\u4E2A\u6027\u80FD\u6D4B\u8BD5\u8FC7\u7A0B\u53EF\u4EE5\u5206\u4E3A\u4E94\u4E2A\u9636\u6BB5\uFF0C\u5E76\u4E14\u89E3\u51B3\u4E86\u6574\u4E2A\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\u6700\u96BE\u7684\u4E00\u90E8\u5206\u5DE5\u4F5C\uFF0C\u5373\u5982\u4F55\u83B7\u53D6\u5177\u4F53\u7684\u6027\u80FD\u6D4B\u8BD5\u9700\u6C42\u3002</p><p>\u73B0\u5728\uFF0C\u6211\u4EEC\u5148\u6765\u56DE\u987E\u4E00\u4E0B\uFF0C\u6027\u80FD\u6D4B\u8BD5\u5305\u542B\u7684\u4E94\u4E2A\u9636\u6BB5\uFF1A\u6027\u80FD\u9700\u6C42\u6536\u96C6\u4EE5\u53CA\u8D1F\u8F7D\u8BA1\u5212\u5236\u5B9A\u3001\u5F55\u5236\u5E76\u589E\u5F3A\u865A\u62DF\u7528\u6237\u811A\u672C\u3001\u521B\u5EFA\u5E76\u5B9A\u4E49\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u3001\u6267\u884C\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\uFF0C\u4EE5\u53CA\u5206\u6790\u6D4B\u8BD5\u62A5\u544A\u3002\u6240\u4EE5\uFF0C\u4ECA\u5929\uFF0C\u6211\u4EEC\u5C31\u8981\u89E3\u51B3\u5269\u4E0B\u7684 4 \u4E2A\u9636\u6BB5\u7684\u95EE\u9898\u4E86\u3002</p><p><strong>\u9636\u6BB5 2\uFF1A\u5F55\u5236\u5E76\u589E\u5F3A\u865A\u62DF\u7528\u6237\u811A\u672C</strong></p><p>\u6211\u5DF2\u7ECF\u5728\u4E0A\u7BC7\u6587\u7AE0\u4E2D\u548C\u4F60\u63D0\u5230\uFF0C\u5B8C\u6210\u4E86\u6027\u80FD\u6D4B\u8BD5\u9700\u6C42\u5206\u6790\u540E\uFF0C\u4F60\u5C31\u5DF2\u7ECF\u660E\u786E\u4E86\u8981\u5F00\u53D1\u54EA\u4E9B\u6027\u80FD\u6D4B\u8BD5\u811A\u672C\u3002\u73B0\u5728\uFF0C\u6211\u4EEC\u5C31\u4E00\u8D77\u6765\u770B\u770B\u5F00\u53D1\u6027\u80FD\u6D4B\u8BD5\u811A\u672C\u7684\u6B65\u9AA4\uFF0C\u4EE5\u53CA\u76F8\u5173\u7684\u6280\u672F\u7EC6\u8282\u3002</p><p>\u4ECE\u6574\u4F53\u89D2\u5EA6\u6765\u770B\uFF0C\u7528 LoadRunner \u5F00\u53D1\u865A\u62DF\u7528\u6237\u811A\u672C\u4E3B\u8981\u5305\u62EC\u4EE5\u4E0B\u56DB\u4E2A\u6B65\u9AA4\uFF1A</p><ol><li>\u8BC6\u522B\u88AB\u6D4B\u5E94\u7528\u4F7F\u7528\u7684\u534F\u8BAE\uFF1B</li><li>\u5F55\u5236\u811A\u672C\uFF1B</li><li>\u5B8C\u5584\u5F55\u5236\u5F97\u5230\u7684\u811A\u672C\uFF1B</li><li>\u9A8C\u8BC1\u811A\u672C\u7684\u6B63\u786E\u6027\u3002</li></ol><p>\u8FD9\u91CC\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0C\u5B8C\u5584\u5F55\u5236\u5F97\u5230\u7684\u811A\u672C\u8FD9\u4E00\u6B65\uFF0C\u4F1A\u5305\u542B\u5927\u91CF\u7684\u6280\u672F\u7EC6\u8282\uFF0C\u4E5F\u6709\u5F88\u591A\u5BF9\u4F60\u6765\u8BF4\u53EF\u80FD\u662F\u65B0\u6982\u5FF5\u7684\u540D\u8BCD\uFF0C\u6240\u4EE5\u6211\u4F1A\u7740\u91CD\u8BB2\u89E3\u8FD9\u4E00\u6B65\uFF0C\u5E2E\u4F60\u514B\u670D\u6027\u80FD\u6D4B\u8BD5\u9053\u8DEF\u4E0A\u7684\u8FD9\u4E9B\u201C\u62E6\u8DEF\u864E\u201D\u3002</p><p><strong>\u6B65\u9AA4 1\uFF1A\u8BC6\u522B\u88AB\u6D4B\u5E94\u7528\u4F7F\u7528\u7684\u534F\u8BAE</strong></p><p>\u5982\u679C\u4F60\u5DF2\u7ECF\u548C\u7CFB\u7EDF\u8BBE\u8BA1\u3001\u5F00\u53D1\u4EBA\u5458\u6C9F\u901A\u8FC7\uFF0C\u660E\u786E\u77E5\u9053\u4E86\u88AB\u6D4B\u7CFB\u7EDF\u6240\u91C7\u7528\u7684\u534F\u8BAE\uFF0C\u90A3\u4E48\u4F60\u53EF\u4EE5\u8DF3\u8FC7\u8FD9\u4E00\u6B65\u3002\u5982\u679C\u8FD8\u4E0D\u77E5\u9053\u5177\u4F53\u4F7F\u7528\u7684\u54EA\u79CD\u534F\u8BAE\u7684\u8BDD\uFF0C\u4F60\u53EF\u4EE5\u4F7F\u7528 Virtual User Generator \u6A21\u5757\u81EA\u5E26\u7684 Protocol Advisor \u8BC6\u522B\u88AB\u6D4B\u5E94\u7528\u4F7F\u7528\u7684\u534F\u8BAE\uFF0C\u5177\u4F53\u7684\u64CD\u4F5C\u65B9\u6CD5\u4E5F\u5F88\u7B80\u5355\uFF1A</p><ol><li>\u5728 Virtual User Generator \u4E2D\u4F9D\u6B21\u70B9\u51FB File\u3001Protocol\u3001AdvisorAnalyze\u3001Application\uFF0C\u5C55\u5F00\u8FD9\u4E9B\u83DC\u5355\u3002</li><li>\u5728\u6253\u5F00\u7684\u754C\u9762\u4E0A\u6309\u8981\u6C42\u586B\u5199\u88AB\u6D4B\u5E94\u7528\u7684\u4FE1\u606F\u3002</li><li>Protocol Advisor \u4F1A\u81EA\u52A8\u8FD0\u884C\u88AB\u6D4B\u7CFB\u7EDF\u3002\u5982\u679C\u662F\u7F51\u9875\u5E94\u7528\uFF0C\u5C31\u4F1A\u6253\u5F00\u6D4F\u89C8\u5668\u3002</li><li>\u5728\u9875\u9762\u4E0A\u6267\u884C\u4E00\u4E9B\u5178\u578B\u7684\u4E1A\u52A1\u64CD\u4F5C\uFF0C\u5B8C\u6210\u8FD9\u4E9B\u4E1A\u52A1\u64CD\u4F5C\u540E\u70B9\u51FB&quot;Stop Analyzing&quot;\u6309\u94AE\u505C\u6B62\u5F55\u5236\u3002</li><li>Protocol Advisor \u4F1A\u6839\u636E\u521A\u624D\u5F55\u5236\u7684\u5185\u5BB9\u81EA\u52A8\u5206\u6790\u88AB\u6D4B\u5E94\u7528\u4F7F\u7528\u7684\u534F\u8BAE\uFF0C\u5E76\u7ED9\u51FA\u6700\u7EC8\u7684\u5EFA\u8BAE\u3002</li></ol><p>\u63A5\u4E0B\u6765\uFF0C\u4F60\u5C31\u53EF\u4EE5\u4F7F\u7528 Protocol Advisor \u5EFA\u8BAE\u7684\u5F55\u5236\u534F\u8BAE\u5F00\u59CB\u811A\u672C\u5F55\u5236\u5DE5\u4F5C\u4E86\u3002\u5982\u56FE 1 \u6240\u793A\u5C31\u662F Protocol Advisor \u7ED9\u51FA\u7684\u5EFA\u8BAE\u5F55\u5236\u534F\u8BAE\u754C\u9762\u3002</p><p><img src="https://static001.geekbang.org/resource/image/9a/20/9a8c760f3de2eaa1c5be274c70215920.png" alt="Protocol Advisor\u7ED9\u51FA\u7684\u5EFA\u8BAE\u5F55\u5236\u534F\u8BAE\u754C\u9762"></p><p><strong>\u6B65\u9AA4 2\uFF1A\u5F55\u5236\u811A\u672C</strong></p><p>\u811A\u672C\u5F55\u5236\u7684\u57FA\u672C\u539F\u7406\u662F\uFF0C\u901A\u8FC7 GUI \u754C\u9762\u5BF9\u88AB\u6D4B\u7CFB\u7EDF\u8FDB\u884C\u4E1A\u52A1\u64CD\u4F5C\uFF0CVirtual User Generator \u6A21\u5757\u5728\u540E\u53F0\u6355\u83B7 GUI \u64CD\u4F5C\u6240\u89E6\u53D1\u7684\u5BA2\u6237\u7AEF\u4E0E\u670D\u52A1\u5668\u7AEF\u7684\u6240\u6709\u4EA4\u4E92\uFF0C\u5E76\u751F\u4EA7\u57FA\u4E8E C \u8BED\u8A00\u7684\u865A\u62DF\u7528\u6237\u811A\u672C\u6587\u4EF6\u3002</p><p>\u4E5F\u5C31\u662F\u8BF4\uFF0C\u5F55\u5236\u811A\u672C\u7684\u8FC7\u7A0B\u9700\u8981\u901A\u8FC7 GUI \u5B9E\u9645\u6267\u884C\u4E1A\u52A1\u64CD\u4F5C\uFF0C\u6240\u4EE5\u6211\u5EFA\u8BAE\u4F60\u5728\u5F00\u59CB\u5F55\u5236\u811A\u672C\u524D\uFF0C\u5148\u591A\u6B21\u6F14\u7EC3\u9700\u8981\u8FD9\u4E9B GUI \u64CD\u4F5C\u6B65\u9AA4\uFF0C\u5E76\u660E\u786E\u77E5\u9053\u54EA\u4E9B\u64CD\u4F5C\u6B65\u9AA4\u4F1A\u5BF9\u670D\u52A1\u5668\u7AEF\u53D1\u8D77\u8BF7\u6C42\u3002</p><p>\u6211\u4EEC\u8981\u77E5\u9053\u54EA\u4E9B\u64CD\u4F5C\u6B65\u9AA4\u4F1A\u5BF9\u670D\u52A1\u5668\u53D1\u8D77\u8BF7\u6C42\u7684\u539F\u56E0\u662F\uFF0C\u8981\u5C06\u8FD9\u4E9B\u64CD\u4F5C\u6B65\u9AA4\u5728\u865A\u62DF\u7528\u6237\u811A\u672C\u4E2D\u5C01\u88C5\u6210\u201C\u4E8B\u52A1\u201D\uFF08Transaction\uFF09\u3002\u5C01\u88C5\u4E3A\u201C\u4E8B\u52A1\u201D\u7684\u76EE\u7684\u662F\u7EDF\u8BA1\u54CD\u5E94\u65F6\u95F4\uFF0C\u56E0\u4E3A LoadRunner \u4E2D\u7684\u54CD\u5E94\u65F6\u95F4\u90FD\u662F\u4EE5\u201C\u4E8B\u52A1\u201D\u4E3A\u5355\u4F4D\u7684\u3002</p><p>\u5177\u4F53\u7684\u5F55\u5236\u6B65\u9AA4\uFF0C\u4E3B\u8981\u5305\u62EC\u5982\u4E0B\u4E09\u6B65\uFF0C</p><ol><li>\u9996\u5148\uFF0C\u9009\u62E9 Create/Edit Scripts \u8FDB\u5165 Virtual User Generator \u521B\u5EFA\u811A\u672C\u7684\u534F\u8BAE\u9009\u62E9\u754C\u9762\u3002</li><li>\u9009\u62E9\u6B63\u786E\u7684\u534F\u8BAE\u540E\u8FDB\u5165 Start Recording \u754C\u9762\uFF0C\u9009\u62E9\u9700\u8981\u5F55\u5236\u7684\u5E94\u7528\u7C7B\u578B\uFF0C\u5E76\u586B\u5199\u5E94\u7528\u7684\u8BE6\u7EC6\u4FE1\u606F\u3002\u5982\u679C\u662F Web \u5E94\u7528\uFF0CApplication type \u5C31\u5E94\u8BE5\u9009\u62E9 Internet Application\uFF0C\u7136\u540E\u9009\u62E9\u6D4F\u89C8\u5668\u5E76\u586B\u5199\u8FD9\u4E2A Web \u5E94\u7528\u7684 URL\uFF0C\u5B8C\u6210\u540E\u81EA\u52A8\u6253\u5F00\u6D4F\u89C8\u5668\u3002</li><li>\u5728\u8BE5\u6D4F\u89C8\u5668\u4E2D\u6267\u884C\u4E1A\u52A1\u64CD\u4F5C\uFF0CVirtual User Generator \u6A21\u5757\u4F1A\u8BB0\u5F55\u6240\u6709\u7684\u4E1A\u52A1\u64CD\u4F5C\uFF0C\u5E76\u751F\u6210\u811A\u672C\u3002</li></ol><p><strong>\u5728\u5F55\u5236\u811A\u672C\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u6211\u5F3A\u70C8\u5EFA\u8BAE\u76F4\u63A5\u5BF9\u53D1\u8D77\u540E\u7AEF\u8C03\u7528\u7684\u64CD\u4F5C\u6DFB\u52A0\u4E8B\u52A1\u5B9A\u4E49\uFF0C\u800C\u4E0D\u8981\u7B49\u5230\u811A\u672C\u751F\u6210\u540E\u518D\u6DFB\u52A0</strong>\u3002\u56E0\u4E3A LoadRunner \u811A\u672C\u7684\u53EF\u8BFB\u6027\u5E76\u4E0D\u597D\uFF0C\u5728\u5F55\u5236\u5B8C\u7684\u811A\u672C\u4E2D\u6DFB\u52A0\u4E8B\u52A1\u5B9A\u4E49\u7684\u96BE\u5EA6\u4F1A\u5F88\u5927\u3002</p><p>\u5728\u5F55\u5236\u8FC7\u7A0B\u4E2D\uFF0C\u76F4\u63A5\u6DFB\u52A0\u4E8B\u52A1\u64CD\u4F5C\u4E5F\u5F88\u7B80\u5355\uFF0C\u4E3B\u8981\u5305\u62EC\u5982\u4E0B\u4E09\u6B65\uFF1A</p><ol><li>\u5728\u5F00\u59CB\u6267\u884C GUI \u64CD\u4F5C\u524D\uFF0C\u5148\u70B9\u51FB\u56FE 2 \u4E2D\u7684\u201C\u4E8B\u52A1\u5F00\u59CB\u201D\u6309\u94AE\u5E76\u586B\u5199\u4E8B\u52A1\u540D\u79F0\uFF1B</li><li>\u6267\u884C GUI \u64CD\u4F5C\uFF1B</li><li>\u64CD\u4F5C\u5B8C\u6210\u540E\uFF0C\u70B9\u51FB\u56FE 2 \u4E2D\u7684\u201C\u4E8B\u52A1\u7ED3\u675F\u201D\u6309\u94AE\u3002</li></ol><p>\u8FD9\u6837\u4F60\u521A\u624D\u6267\u884C GUI \u64CD\u4F5C\u7684\u811A\u672C\u5C31\u4F1A\u88AB lr_start_transaction(\u201C\u4E8B\u52A1\u540D\u79F0\u201D)\u548C lr_end_transaction(\u201C\u4E8B\u52A1\u540D\u79F0\u201D\uFF0CLR_AUTO)\u5305\u56F4\u8D77\u6765\uFF0C\u4E5F\u5C31\u5B8C\u6210\u4E86\u6DFB\u52A0\u4E8B\u52A1\u7684\u5B9A\u4E49\u3002</p><p><img src="https://static001.geekbang.org/resource/image/66/34/6636bbd8056a7e992239fbb3b81bf134.png" alt="Virtual User Generator\u7684\u811A\u672C\u5F55\u5236\u63A7\u5236\u6761"></p><p><strong>\u6B65\u9AA4 3\uFF1A\u5B8C\u5584\u5F55\u5236\u5F97\u5230\u7684\u811A\u672C</strong></p><p>\u811A\u672C\u5F55\u5236\uFF0C\u53EA\u662F\u865A\u62DF\u7528\u6237\u811A\u672C\u5F00\u53D1\u4E2D\u6700\u7B80\u5355\u7684\u4E00\u6B65\u3002\u6211\u5728\u4E0A\u4E00\u6B21\u5206\u4EAB\u300A\u65E0\u5B9E\u4F8B\u65E0\u771F\u76F8\uFF1A\u57FA\u4E8E LoadRunner \u5B9E\u73B0\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5B9E\u8DF5\uFF08\u4E0A\uFF09\u300B\u65F6\uFF0C\u63D0\u5230\u7531 Virtual User Generator \u6A21\u5757\u5F55\u5236\u7684\u811A\u672C\u4E0D\u80FD\u76F4\u63A5\u4F7F\u7528\uFF0C\u6211\u4EEC\u8FD8\u9700\u8981\u5BF9\u5F55\u5236\u7684\u811A\u672C\u505A\u4EE5\u4E0B\u5904\u7406\uFF1A</p><ul><li>\u5728\u4E24\u4E2A\u4E8B\u52A1\u4E4B\u95F4\u52A0\u5165\u601D\u8003\u65F6\u95F4\uFF08Think Time\uFF09\uFF1B</li><li>\u5BF9\u754C\u9762\u8F93\u5165\u7684\u6570\u636E\u505A\u53C2\u6570\u5316\uFF08Parameterization\uFF09\u64CD\u4F5C\uFF1B</li><li>\u5B8C\u6210\u811A\u672C\u7684\u5173\u8054\uFF08Correlation\uFF09\u64CD\u4F5C\uFF1B</li><li>\u52A0\u5165\u68C0\u67E5\u70B9\uFF08Check Point\uFF09\u3002</li></ul><p>\u8FD9 4 \u6B65\u5904\u7406\u64CD\u4F5C\u662F\u865A\u62DF\u7528\u6237\u811A\u672C\u5F00\u53D1\u4E2D\u6700\u5173\u952E\u7684\u5730\u65B9\uFF0C\u4F60\u4E0D\u4EC5\u9700\u8981\u77E5\u9053\u4E3A\u4EC0\u4E48\u8981\u8FDB\u884C\u8FD9\u4E9B\u5904\u7406\uFF0C\u66F4\u8981\u80FD\u591F\u5B8C\u6210\u8FD9\u4E9B\u5904\u7406\uFF0C\u5426\u5219\u4F60\u5F55\u5236\u7684\u811A\u672C\u65E0\u6CD5\u6210\u529F\u56DE\u653E\u3002</p><p><strong>\u7B2C\u4E00\uFF0C\u5728\u4E24\u4E2A\u4E8B\u52A1\u4E4B\u95F4\u52A0\u5165\u601D\u8003\u65F6\u95F4</strong></p><p>\u4EC0\u4E48\u662F\u601D\u8003\u65F6\u95F4\u5462\uFF1F</p><p>\u7528\u6237\u5728\u5B9E\u9645\u4F7F\u7528\u7CFB\u7EDF\u65F6\uFF0C\u5E76\u4E0D\u4F1A\u8FDE\u7EED\u4E0D\u65AD\u5730\u5411\u540E\u7AEF\u670D\u52A1\u5668\u53D1\u8D77\u8BF7\u6C42\uFF0C\u5728\u4E24\u6B21\u53D1\u8D77\u8BF7\u6C42\u4E4B\u95F4\u5F80\u5F80\u4F1A\u6709\u4E00\u4E2A\u65F6\u95F4\u7684\u95F4\u9694\uFF0C\u8FD9\u4E2A\u65F6\u95F4\u95F4\u9694\u4E3B\u8981\u6765\u81EA\u4E8E\u4E24\u4E2A\u65B9\u9762\uFF1A</p><ul><li>\u4E00\u662F\uFF0C\u7528\u6237\u64CD\u4F5C\u7684\u4EBA\u4E3A\u7B49\u5F85\u65F6\u95F4\uFF0C\u56E0\u4E3A\u7528\u6237\u4E0D\u53EF\u80FD\u50CF\u673A\u5668\u4EBA\u90A3\u6837\u5FEB\u901F\u5730\u6267\u884C\u64CD\u4F5C\uFF1B</li><li>\u4E8C\u662F\uFF0C\u7528\u6237\u53EF\u80FD\u9700\u8981\u5148\u5728\u9875\u9762\u4E0A\u586B\u5199\u5F88\u591A\u4FE1\u606F\u540E\u4E4B\u540E\uFF0C\u624D\u80FD\u63D0\u4EA4\u64CD\u4F5C\uFF0C\u90A3\u4E48\u586B\u5199\u8FD9\u4E9B\u4FE1\u606F\u5C31\u9700\u8981\u82B1\u8D39\u4E00\u5B9A\u7684\u65F6\u95F4\u3002</li></ul><p>\u6240\u4EE5\uFF0C\u4E3A\u4E86\u8BA9\u865A\u62DF\u7528\u6237\u811A\u672C\u80FD\u591F\u66F4\u771F\u5B9E\u5730\u6A21\u62DF\u5B9E\u9645\u7528\u6237\u7684\u884C\u4E3A\uFF0C\u6211\u4EEC\u5C31\u9700\u8981\u5728\u4E24\u4E2A\u4E8B\u52A1\u4E4B\u95F4\u52A0\u5165\u4E00\u5B9A\u7684\u7B49\u5F85\u65F6\u95F4\u3002\u8FD9\u4E2A\u7B49\u5F85\u65F6\u95F4\uFF0C\u5C31\u662F LoadRunner \u4E2D\u7684\u601D\u8003\u65F6\u95F4\u3002</p><p>\u4F60\u53EA\u8981\u76F4\u63A5\u8C03\u7528 LoadRunner \u63D0\u4F9B\u7684 lr_think_time()\u51FD\u6570\uFF0C\u5C31\u53EF\u4EE5\u5728\u4E24\u4E2A\u4E8B\u52A1\u4E4B\u95F4\u52A0\u5165\u601D\u8003\u65F6\u95F4\u3002\u4F46\u662F\uFF0C\u8FD9\u4E2A\u601D\u8003\u65F6\u95F4\u5230\u5E95\u8BBE\u7F6E\u4E3A\u591A\u5C11\uFF0C\u5E76\u6CA1\u6709\u90A3\u4E48\u5BB9\u6613\u77E5\u9053\u3002\u601D\u8003\u65F6\u95F4\u5F80\u5F80\u4F1A\u6D89\u53CA\u591A\u65B9\u9762\u7684\u56E0\u7D20\uFF0C\u4E25\u683C\u8BA1\u7B97\u7684\u8BDD\u4F1A\u975E\u5E38\u590D\u6742\u3002</p><p>\u6240\u4EE5\uFF0C<strong>\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\uFF0C\u4E00\u822C\u5148\u7C97\u7565\u4F30\u8BA1\u4E00\u4E2A\u503C\uFF08\u6BD4\u5982 15 s\uFF09\uFF0C\u7136\u540E\u5728\u5B9E\u9645\u6267\u884C\u8D1F\u8F7D\u573A\u666F\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u518D\u6839\u636E\u7CFB\u7EDF\u541E\u5410\u91CF\u8C03\u6574</strong>\u3002</p><p>\u4F60\u5728\u540E\u7EED\u8C03\u6574\u601D\u8003\u65F6\u95F4\u65F6\uFF0C\u65E0\u9700\u9010\u884C\u4FEE\u6539\u865A\u62DF\u7528\u6237\u811A\u672C\u4EE3\u7801\uFF0C\u53EF\u4EE5\u5728 Run-time Settings\uFF08\u8FD0\u884C\u65F6\u8BBE\u7F6E\uFF09\u4E2D\u5F88\u65B9\u4FBF\u5730\u5B8C\u6210\u3002\u5982\u56FE 3 \u6240\u793A\uFF0CRun-time Settings \u4E2D\u652F\u6301\u591A\u79CD\u65B9\u5F0F\u8C03\u6574\u601D\u8003\u65F6\u95F4\u3002</p><p><img src="https://static001.geekbang.org/resource/image/9b/9b/9bc228a755cb104b34bcc55e6e460c9b.png" alt="\u901A\u8FC7Run-time Settings\u7EDF\u4E00\u8C03\u6574\u601D\u8003\u65F6\u95F4"></p><ul><li>As recorded\uFF0C\u4EE3\u8868\u7684\u662F\u76F4\u63A5\u4F7F\u7528 lr_think_time()\u51FD\u6570\u4E2D\u6307\u5B9A\u7684\u65F6\u95F4\u3002 Mutiply recorded think time by\uFF0C\u4EE3\u8868\u7684\u662F\u5728 lr_think_time()\u51FD\u6570\u4E2D\u6307\u5B9A\u7684\u65F6\u95F4\u57FA\u7840\u4E0A\u4E58\u4EE5\u4E00\u4E2A\u6570\u5B57\u3002\u6BD4\u5982\u8FD9\u4E2A\u6570\u5B57\u662F 2\uFF0C\u90A3\u4E48\u6240\u6709\u7684\u601D\u8003\u65F6\u95F4\u90FD\u4F1A\u7FFB\u500D\u3002</li><li>Use random percentage of recorded think time\uFF0C\u6307\u7684\u662F\u4F7F\u7528\u6307\u5B9A\u601D\u8003\u65F6\u95F4\u8303\u56F4\u5185\u7684\u968F\u673A\u503C\u3002\u4F8B\u5982\uFF0C\u5982\u679C lr_think_time()\u51FD\u6570\u4E2D\u6307\u5B9A\u7684\u65F6\u95F4\u662F 2 s\uFF0C\u5E76\u4E14\u6307\u5B9A\u6700\u5C0F\u503C\u4E3A 50%\uFF0C\u6700\u5927\u503C\u4E3A 200%\uFF0C\u5219\u5B9E\u9645\u7684\u601D\u8003\u65F6\u95F4\u4F1A\u53D6\u6700\u5C0F\u503C 1 s\uFF082 s50%\uFF09\u548C\u6700\u5927\u503C 4 s\uFF082 s200%\uFF09\u4E4B\u95F4\u7684\u968F\u673A\u503C\u3002</li><li>Limit think time to\uFF0C\u6307\u7684\u662F\u4E3A\u601D\u8003\u65F6\u95F4\u8BBE\u7F6E\u4E00\u4E2A\u4E0A\u9650\u503C\uFF0C\u53EA\u8981 lr_think_time()\u51FD\u6570\u4E2D\u6307\u5B9A\u7684\u65F6\u95F4\u6CA1\u6709\u8D85\u8FC7\u8FD9\u4E2A\u4E0A\u9650\u503C\uFF0C\u5C31\u6309\u7167 lr_think_time()\u51FD\u6570\u6307\u5B9A\u7684\u503C\uFF0C\u5982\u679C\u8D85\u8FC7\u4E86\u5C31\u53D6\u8FD9\u4E2A\u4E0A\u9650\u503C\u4F5C\u4E3A\u601D\u8003\u65F6\u95F4\u3002</li></ul><p><strong>\u7B2C\u4E8C\uFF0C\u5BF9\u754C\u9762\u8F93\u5165\u7684\u6570\u636E\u505A\u53C2\u6570\u5316\u64CD\u4F5C</strong></p><p>\u6570\u636E\u7684\u53C2\u6570\u5316\uFF0C\u5176\u5B9E\u5F88\u597D\u7406\u89E3\uFF0C\u6211\u518D\u7ED9\u4F60\u4E3E\u4E2A\u4F8B\u5B50\uFF0C\u4F60\u9A6C\u4E0A\u5C31\u80FD\u660E\u767D\u3002</p><p>\u5047\u8BBE\uFF0C\u4F60\u5F55\u5236\u7684\u865A\u62DF\u7528\u6237\u811A\u672C\u5B8C\u6210\u7684\u662F\u7528\u6237\u767B\u5F55\u64CD\u4F5C\uFF0C\u90A3\u4E48\u7531\u4E8E\u811A\u672C\u56DE\u653E\u65F6\u9700\u8981\u652F\u6301\u591A\u7528\u6237\u7684\u5E76\u53D1\uFF0C\u6240\u4EE5\u5FC5\u987B\u8981\u628A\u811A\u672C\u4E2D\u7684\u7528\u6237\u540D\u548C\u5BC6\u7801\u72EC\u7ACB\u51FA\u6765\uFF0C\u653E\u5165\u4E13\u95E8\u7684\u6570\u636E\u6587\u4EF6\u4E2D\uFF0C\u7136\u540E\u5728\u8FD9\u4E2A\u6587\u4EF6\u4E2D\u63D0\u4F9B\u6240\u6709\u53EF\u80FD\u88AB\u7528\u5230\u7684\u7528\u6237\u540D\u548C\u5BC6\u7801\u3002</p><p>\u6709\u6CA1\u6709\u611F\u89C9\u8FD9\u4E2A\u6982\u5FF5\u5F88\u719F\u6089\uFF0C\u5B83\u5176\u5B9E\u548C\u6211\u4EE5\u524D\u4ECB\u7ECD\u5230\u7684\u6570\u636E\u9A71\u52A8\u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u5B8C\u5168\u76F8\u540C\u3002</p><p>\u56FE 4 \u7ED9\u51FA\u4E86\u53C2\u6570\u5316\u914D\u7F6E\u7684\u754C\u9762\u622A\u56FE\uFF0CLoadRunner \u652F\u6301\u7684\u53C2\u6570\u5316\u7684\u6570\u636E\u6E90\u5F88\u4E30\u5BCC\uFF0C\u65E2\u53EF\u4EE5\u662F excel \u6587\u4EF6\uFF0C\u4E5F\u53EF\u4EE5\u662F\u6570\u636E\u5E93\u4E2D\u7684\u8868\u7B49\u3002</p><p><img src="https://static001.geekbang.org/resource/image/41/77/414fcea000ef8a968cd25d5fbc5ee477.png" alt="\u865A\u62DF\u7528\u6237\u811A\u672C\u53C2\u6570\u5316\u914D\u7F6E\u7684\u754C\u9762\u622A\u56FE"></p><p>\u8FD9\u91CC\u9700\u8981\u7279\u522B\u8BF4\u660E\u7684\u662F\uFF0C\u51E1\u662F\u53C2\u6570\u6587\u4EF6\u4E2D\u4F7F\u7528\u7684\u6D4B\u8BD5\u6570\u636E\u90FD\u9700\u8981\u5728\u6267\u884C\u6027\u80FD\u6D4B\u8BD5\u524D\uFF0C\u5728\u88AB\u6D4B\u7CFB\u7EDF\u4E2D\u4E8B\u5148\u51C6\u5907\u597D\u3002\u6BD4\u5982\uFF0C\u8FD8\u662F\u4EE5\u7528\u6237\u767B\u5F55\u7684\u811A\u672C\u4E3A\u4F8B\uFF0C\u5047\u5B9A\u4F60\u7684\u53C2\u6570\u6587\u4EF6\u4E2D\u63D0\u4F9B\u4E86 5000 \u4E2A\u7528\u4E8E\u5E76\u53D1\u6267\u884C\u7684\u7528\u6237\u4FE1\u606F\uFF0C\u90A3\u4E48\u8FD9 5000 \u4E2A\u7528\u6237\u5FC5\u987B\u662F\u5DF2\u7ECF\u5B9E\u9645\u5B58\u5728\u4E8E\u7CFB\u7EDF\u4E2D\u7684\uFF0C\u8FD9\u5C31\u8981\u6C42\u4F60\u8981\u5728\u5F00\u59CB\u6D4B\u8BD5\u524D\u4E8B\u5148\u51C6\u5907\u597D\u8FD9 5000 \u4E2A\u7528\u6237\u3002</p><p>\u6240\u4EE5\uFF0C\u53C2\u6570\u5316\u64CD\u4F5C\u5176\u5B9E\u7531\u4E24\u90E8\u5206\u7EC4\u6210\uFF1A</p><ol><li>\u6027\u80FD\u6D4B\u8BD5\u811A\u672C\u548C\u6D4B\u8BD5\u6570\u636E\u7684\u5206\u79BB\uFF1B</li><li>\u4E8B\u5148\u5EFA\u7ACB\u6027\u80FD\u6D4B\u8BD5\u7684\u6570\u636E\u3002</li></ol><p>\u4E5F\u5C31\u662F\u8BF4\uFF0C\u53C2\u6570\u5316\u7684\u8FC7\u7A0B\u5F80\u5F80\u4E0E\u6027\u80FD\u6D4B\u8BD5\u6570\u636E\u51C6\u5907\u5BC6\u4E0D\u53EF\u5206\u3002</p><p><strong>\u7B2C\u4E09\uFF0C\u5B8C\u6210\u811A\u672C\u7684\u5173\u8054\u64CD\u4F5C</strong></p><p>\u5173\u8054\u64CD\u4F5C\uFF0C\u662F LoadRunner \u865A\u62DF\u7528\u6237\u811A\u672C\u5F00\u53D1\u8FC7\u7A0B\u4E2D\u6700\u5173\u952E\u7684\u90E8\u5206\uFF0C\u76F4\u63A5\u5173\u7CFB\u5230\u811A\u672C\u662F\u5426\u53EF\u4EE5\u56DE\u653E\u6210\u529F\u3002</p><p>\u4ECE\u6982\u5FF5\u4E0A\u8BB2\uFF0C\u5173\u8054\u7684\u4E3B\u8981\u4F5C\u7528\u662F\uFF0C\u53D6\u51FA\u524D\u5E8F\u8C03\u7528\u8FD4\u56DE\u7ED3\u679C\u4E2D\u7684\u67D0\u4E9B\u52A8\u6001\u503C\uFF0C\u4F20\u9012\u7ED9\u540E\u7EED\u7684\u8C03\u7528\u3002\u662F\u4E0D\u662F\u542C\u8D77\u6765\u5F88\u62D7\u53E3\uFF0C\u4E0D\u592A\u597D\u7406\u89E3\uFF1F\u6211\u4EEC\u6765\u770B\u4E00\u4E2A\u5177\u4F53\u7684\u4F8B\u5B50\u5427\u3002</p><p>\u5047\u8BBE\uFF0C\u6BCF\u6B21\u5BA2\u6237\u7AEF\u8FDE\u63A5\u670D\u52A1\u5668\u7AEF\u65F6\uFF0C\u670D\u52A1\u5668\u7AEF\u90FD\u4F1A\u7528\u5F53\u524D\u7684\u65F6\u95F4\u6233\uFF08Time Stamp\uFF09\u8BA1\u7B97 CheckSum\uFF0C\u7136\u540E\u5C06 Time Stamp \u548C CheckSum \u8FD4\u56DE\u7ED9\u5BA2\u6237\u7AEF\u3002\u7136\u540E\uFF0C\u5BA2\u6237\u7AEF\u5C31\u628A Time Stamp + CheckSum \u7684\u7EC4\u5408\u4F5C\u4E3A\u552F\u4E00\u6807\u8BC6\u5BA2\u6237\u7AEF\u7684 Session ID\u3002\u5F55\u5236\u811A\u672C\u65F6\uFF0C\u5F55\u5236\u5F97\u5230\u7684\u4E00\u5B9A\u662F\u786C\u7F16\u7801\uFF08hardcode\uFF09\u7684 Time Stamp \u503C\u548C CheckSum \u503C\u3002</p><p>\u56FE 5 \u5C55\u793A\u4E86\u8FD9\u4E2A\u4EA4\u4E92\u8FC7\u7A0B\uFF0C\u5F55\u5236\u5F97\u5230 Time Stamp \u7684\u503C\u662F TS\uFF0C\u800C CheckSum \u7684\u503C\u662F CS\u3002</p><p><img src="https://static001.geekbang.org/resource/image/f2/02/f275c421d12a323f9ddcff63a4873c02.png" alt="\u5173\u8054\u539F\u7406\u56FE-\u811A\u672C\u5F55\u5236\u8FC7\u7A0B"></p><p>\u91C7\u7528 Time Stamp + CheckSum \u7684\u7EC4\u5408\u4F5C\u4E3A Session ID \u7684\u65B9\u5F0F\uFF0C\u5728\u6211\u4EEC\u56DE\u653E\u8FD9\u4E2A\u811A\u672C\u7684\u65F6\u5019\u5C31\u6709\u95EE\u9898\u4E86\u3002\u56E0\u4E3A\u56DE\u653E\u65F6\uFF0C\u8FD9\u6BB5\u786C\u7F16\u7801\u5DF2\u7ECF\u6709\u4E86\u65B0\u7684 Time Stamp \u503C\u548C CheckSum \u503C\uFF0C\u5E76\u4E14\u663E\u7136\u4E0E\u4E4B\u524D\u7684\u503C\u4E0D\u540C\uFF0C\u6240\u4EE5\u670D\u52A1\u5668\u65E0\u6CD5\u5B8C\u6210 Session ID \u7684\u9A8C\u8BC1\uFF0C\u4E5F\u5C31\u5BFC\u81F4\u4E86\u811A\u672C\u56DE\u653E\u5931\u8D25\u3002</p><p><img src="https://static001.geekbang.org/resource/image/d8/df/d8cdec2de5664b2d5b4288514c9cd4df.png" alt="\u5173\u8054\u539F\u7406\u56FE-\u811A\u672C\u56DE\u653E\u8FC7\u7A0B"></p><p>\u5176\u5B9E\uFF0C\u8FD9\u79CD\u60C5\u51B5\u51E0\u4E4E\u5B58\u5728\u4E8E\u6240\u6709\u7684\u865A\u62DF\u7528\u6237\u811A\u672C\u4E2D\uFF0C\u6240\u4EE5\u6211\u4EEC\u5FC5\u987B\u8981\u89E3\u51B3\u8FD9\u4E2A\u95EE\u9898\u3002</p><p>\u89E3\u51B3\u65B9\u6CD5\u5C31\u662F\uFF0C\u5728\u811A\u672C\u56DE\u653E\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u5B9E\u65F6\u6293\u53D6 Time Stamp \u503C\u548C CheckSum \u503C\uFF0C\u7136\u540E\u7528\u5B9E\u65F6\u6293\u53D6\u5230\u7684\u503C\u66FF\u6362\u540E\u7EED\u9700\u8981\u4F7F\u7528\u8FD9\u4E24\u4E2A\u503C\u7684\u5730\u65B9\u3002\u8FD9\u4E2A\u8FC7\u7A0B\u5C31\u662F\u201C\u5173\u8054\u201D\u3002</p><p>\u5982\u56FE 7 \u6240\u793A\uFF0C<strong>\u5173\u8054\u5C31\u662F\u89E3\u6790\u670D\u52A1\u5668\u7AEF\u7684\u8FD4\u56DE\u7ED3\u679C\uFF0C\u6293\u53D6\u65B0\u7684 Time Stamp \u503C\u548C CheckSum \u503C\uFF0C\u7136\u540E\u540E\u7EED\u7684\u64CD\u4F5C\u90FD\u4F7F\u7528\u65B0\u6293\u53D6\u7684\u503C\uFF0C\u8FD9\u6837\u811A\u672C\u5C31\u80FD\u56DE\u653E\u6210\u529F\u4E86</strong>\u3002</p><p><img src="https://static001.geekbang.org/resource/image/33/8f/33675b6e6a3b008cb3ebb16af58e6a8f.png" alt="\u5173\u8054\u539F\u7406\u56FE-\u4F7F\u7528\u201C\u5173\u8054\u201D\u540E\u7684\u811A\u672C\u56DE\u653E\u8FC7\u7A0B"></p><p>\u7406\u89E3\u4E86\u5173\u8054\u64CD\u4F5C\uFF0C\u5728\u811A\u672C\u4E2D\u5904\u7406\u5173\u8054\u5C31\u6BD4\u8F83\u7B80\u5355\u4E86\uFF0CLoadRunner \u63D0\u4F9B\u4E86\u529F\u80FD\u5F3A\u5927\u7684\u5173\u8054\u51FD\u6570 web_reg_save_param()\u3002\u8FD9\u4E2A\u5173\u8054\u51FD\u6570\u652F\u6301\u591A\u79CD\u52A8\u6001\u503C\u7684\u83B7\u53D6\u65B9\u5F0F\uFF0C\u7528\u5F97\u6700\u591A\u7684\u662F\u57FA\u4E8E\u201C\u524D\u5E8F\u5B57\u7B26\u4E32\u5339\u914D\u201D\u52A0\u4E0A\u201C\u540E\u7EED\u5B57\u7B26\u4E32\u5339\u914D\u201D\u7684\u65B9\u5F0F\u3002\u5176\u4E2D\uFF0C\u5B57\u7B26\u4E32\u5339\u914D\uFF0C\u652F\u6301\u6B63\u5219\u8868\u8FBE\u5F0F\u3002</p><p>\u6211\u4EEC\u4E00\u8D77\u6765\u770B\u4E2A\u5177\u4F53\u7684\u4F8B\u5B50\u5427\u3002</p><p>\u5047\u8BBE\uFF0C\u670D\u52A1\u5668\u7AEF\u8FD4\u56DE\u7684\u7ED3\u679C\u662F\u201CLB=name=timestamp value=8888.LB=name=CheckSum\u201D\uFF0C\u90A3\u4E48\u4E3A\u4E86\u80FD\u591F\u83B7\u53D6\u5230\u201C8888\u201D\u8FD9\u4E2A\u52A8\u6001\u503C\uFF0C\u6211\u4EEC\u5C31\u53EF\u4EE5\u7528\u201C\u524D\u5E8F\u5B57\u7B26\u4E32=LB=name=timestamp value=\u201D\u548C\u201C\u540E\u7EED\u5B57\u7B26=.LB=name=CheckSum\u201D\u6765\u201C\u6846\u51FA\u201D 8888\u201D\u8FD9\u4E2A\u52A8\u6001\u503C\u3002</p><p>\u53E6\u5916\uFF0C\u9700\u8981\u7279\u522B\u6CE8\u610F\u7684\u662F web_reg_save_param()\u51FD\u6570\u662F\u6CE8\u518C\u578B\u51FD\u6570\uFF0C\u5FC5\u987B\u653E\u5728\u83B7\u53D6\u52A8\u6001\u503C\u6240\u5C5E\u7684\u8BF7\u6C42\u524D\u9762\uFF0C\u76F8\u5F53\u4E8E\u5148\u58F0\u660E\uFF0C\u540E\u8C03\u7528\u3002</p><p>\u66F4\u591A\u7684\u5173\u8054\u51FD\u6570\u7528\u6CD5\uFF0C\u4F60\u53EF\u4EE5\u53C2\u8003 LoadRunner \u5B98\u65B9\u6587\u6863\u3002</p><p><strong>\u7B2C\u56DB\uFF0C\u52A0\u5165\u68C0\u67E5\u70B9</strong></p><p>\u68C0\u67E5\u70B9\uFF0C\u7C7B\u4F3C\u4E8E\u529F\u80FD\u6D4B\u8BD5\u4E2D\u7684\u65AD\u8A00\u3002\u4F46\u662F\uFF0C\u6027\u80FD\u6D4B\u8BD5\u811A\u672C\uFF0C\u4E0D\u50CF\u529F\u80FD\u6D4B\u8BD5\u811A\u672C\u90A3\u6837\u9700\u8981\u52A0\u5165\u5F88\u591A\u7684\u65AD\u8A00\uFF0C\u5F80\u5F80\u53EA\u5728\u4E00\u4E9B\u5173\u952E\u6B65\u9AA4\u540E\u52A0\u5165\u5F88\u5C11\u91CF\u7684\u68C0\u67E5\u70B9\u5373\u53EF\u3002\u8FD9\u4E9B\u68C0\u67E5\u70B9\u7684\u4E3B\u8981\u4F5C\u7528\u662F\uFF0C\u4FDD\u8BC1\u811A\u672C\u6309\u7167\u539F\u672C\u8BBE\u8BA1\u7684\u8DEF\u5F84\u6267\u884C\u3002</p><p>\u6700\u5E38\u7528\u7684\u68C0\u67E5\u70B9\u51FD\u6570\u662F web_reg_find()\uFF0C\u5B83\u7684\u4F5C\u7528\u662F\u901A\u8FC7\u6307\u5B9A\u5DE6\u53F3\u8FB9\u754C\u7684\u65B9\u5F0F\u201C\u5728\u9875\u9762\u4E2D\u67E5\u627E\u76F8\u5E94\u7684\u5185\u5BB9\u201D\u3002\u8FD9\u91CC\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0C\u8FD9\u4E2A\u51FD\u6570\u4E5F\u662F\u6CE8\u518C\u578B\u51FD\u6570\uFF0C\u5373\u9700\u8981\u653E\u5728\u6240\u68C0\u67E5\u7684\u9875\u9762\u4E4B\u524D\uFF0C\u5426\u5219\u4F1A\u68C0\u67E5\u5931\u8D25\u3002\u66F4\u591A\u7684\u68C0\u67E5\u70B9\u51FD\u6570\u4EE5\u53CA\u7528\u6CD5\u4E5F\u8BF7\u53C2\u8003 LoadRunner \u5B98\u65B9\u6587\u6863\u3002</p><p><strong>\u6B65\u9AA4 4\uFF1A\u9A8C\u8BC1\u811A\u672C\u7684\u6B63\u786E\u6027</strong></p><p>\u5B8C\u6210\u4E86\u811A\u672C\u5F00\u53D1\u540E\uFF0C\u6839\u636E\u6211\u7684\u4E2A\u4EBA\u7ECF\u9A8C\uFF0C\u6211\u5F3A\u70C8\u5EFA\u8BAE\u4F60\u6309\u7167\u4EE5\u4E0B\u987A\u5E8F\u68C0\u67E5\u811A\u672C\u7684\u51C6\u786E\u6027\uFF1A</p><p>\u4EE5\u5355\u7528\u6237\u7684\u65B9\u5F0F\uFF0C\u5728\u6709\u601D\u8003\u65F6\u95F4\u7684\u60C5\u51B5\u4E0B\u6267\u884C\u811A\u672C\uFF0C\u786E\u4FDD\u811A\u672C\u80FD\u591F\u987A\u5229\u6267\u884C\uFF0C\u5E76\u4E14\u9A8C\u8BC1\u811A\u672C\u884C\u4E3A\u4EE5\u53CA\u6267\u884C\u7ED3\u679C\u662F\u5426\u6B63\u786E\uFF1B</p><p>\u4EE5\u5355\u7528\u6237\u7684\u65B9\u5F0F\uFF0C\u5728\u601D\u8003\u65F6\u95F4\u4E3A\u96F6\u7684\u60C5\u51B5\u4E0B\u6267\u884C\u811A\u672C\uFF0C\u786E\u4FDD\u811A\u672C\u80FD\u591F\u987A\u5229\u6267\u884C\uFF0C\u5E76\u4E14\u9A8C\u8BC1\u811A\u672C\u884C\u4E3A\u4EE5\u53CA\u6267\u884C\u7ED3\u679C\u662F\u5426\u6B63\u786E\uFF1B</p><p>\u4EE5\u5E76\u53D1\u7528\u6237\u7684\u65B9\u5F0F\uFF0C\u5728\u6709\u601D\u8003\u65F6\u95F4\u7684\u60C5\u51B5\u4E0B\u6267\u884C\u811A\u672C\uFF0C\u786E\u4FDD\u811A\u672C\u80FD\u591F\u987A\u5229\u6267\u884C\uFF0C\u5E76\u4E14\u9A8C\u8BC1\u811A\u672C\u884C\u4E3A\u4EE5\u53CA\u6267\u884C\u7ED3\u679C\u662F\u5426\u6B63\u786E\uFF1B</p><p>\u4EE5\u5E76\u53D1\u7528\u6237\u7684\u65B9\u5F0F\uFF0C\u5728\u601D\u8003\u65F6\u95F4\u4E3A\u96F6\u7684\u60C5\u51B5\u4E0B\u6267\u884C\u811A\u672C\uFF0C\u786E\u4FDD\u811A\u672C\u80FD\u591F\u987A\u5229\u6267\u884C\uFF0C\u5E76\u4E14\u9A8C\u8BC1\u811A\u672C\u884C\u4E3A\u4EE5\u53CA\u6267\u884C\u7ED3\u679C\u662F\u5426\u6B63\u786E\u3002</p><p>\u53EA\u6709\u4E0A\u8FF0\u56DB\u4E2A\u6D4B\u8BD5\u5168\u90E8\u901A\u8FC7\uFF0C\u865A\u62DF\u7528\u6237\u811A\u672C\u624D\u7B97\u987A\u5229\u5B8C\u6210\u3002</p><p>\u81F3\u6B64\uFF0C\u6211\u4EEC\u5B8C\u6210\u4E86\u7B2C\u4E8C\u4E2A\u9636\u6BB5\u7684\u201C\u5F55\u5236\u5E76\u589E\u5F3A\u865A\u62DF\u7528\u6237\u811A\u672C\u201D\u7684\u5DE5\u4F5C\uFF0C\u987A\u5229\u62FF\u5230\u4E86\u865A\u62DF\u7528\u6237\u811A\u672C\u3002\u90A3\u4E48\u63A5\u4E0B\u6765\uFF0C\u6211\u4EEC\u5C31\u4F1A\u8FDB\u5165\u7B2C\u4E09\u4E2A\u9636\u6BB5\uFF0C\u4F7F\u7528\u5F00\u53D1\u5B8C\u6210\u7684\u865A\u62DF\u7528\u6237\u811A\u672C\u521B\u5EFA\u5E76\u5B9A\u4E49\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u3002</p><p><strong>\u9636\u6BB5 3\uFF1A\u521B\u5EFA\u5E76\u5B9A\u4E49\u6027\u80FD\u6D4B\u8BD5\u573A\u666F</strong></p><p>\u8FD8\u8BB0\u5F97\u6211\u5728\u5206\u4EAB\u300A\u5DE5\u6B32\u5584\u5176\u4E8B\u5FC5\u5148\u5229\u5176\u5668\uFF1A\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u539F\u7406\u4E0E\u884C\u4E1A\u5E38\u7528\u5DE5\u5177\u7B80\u4ECB\u300B\u8FD9\u4E2A\u4E3B\u9898\u65F6\uFF0C\u4ECB\u7ECD\u8FC7\u7684\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u7684\u5185\u5BB9\u5417\uFF1F\u5982\u679C\u6709\u70B9\u5FD8\u8BB0\u4E86\uFF0C\u6211\u5EFA\u8BAE\u4F60\u5148\u56DE\u987E\u4E00\u4E0B\u8FD9\u7BC7\u6587\u7AE0\u7684\u5185\u5BB9\u3002</p><p>\u8FD9\u4E2A\u9636\u6BB5\u7684\u5DE5\u4F5C\uFF0C\u5C31\u662F\u5728 LoadRunner Controller \u4E2D\u8BBE\u7F6E\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u3002\u7531\u4E8E\u6574\u4E2A\u8BBE\u7F6E\u8FC7\u7A0B\uFF0C\u90FD\u662F\u57FA\u4E8E Controller \u7684\u56FE\u5F62\u7528\u6237\u754C\u9762\u7684\u64CD\u4F5C\uFF0C\u672C\u8EAB\u6CA1\u4EC0\u4E48\u96BE\u5EA6\uFF0C\u6240\u4EE5\u6211\u5C31\u4E0D\u518D\u8BE6\u7EC6\u5C55\u5F00\u4E86\uFF0C\u5982\u679C\u6709\u8FD9\u65B9\u9762\u7684\u95EE\u9898\uFF0C\u4F60\u4E5F\u53EF\u4EE5\u81EA\u884C\u767E\u5EA6\u6216\u8005\u7ED9\u6211\u7559\u8A00\u3002</p><p><strong>\u9636\u6BB5 4\uFF1A\u6267\u884C\u6027\u80FD\u6D4B\u8BD5\u573A\u666F</strong></p><p>\u5B8C\u6210\u4E86\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u7684\u8BBE\u8BA1\u4E0E\u5B9A\u4E49\u540E\uFF0C\u6267\u884C\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u5C31\u975E\u5E38\u7B80\u5355\u4E86\u3002</p><p>\u8FD9\u4E2A\u8FC7\u7A0B\u4E00\u822C\u662F\u5728 LoadRunner Controller \u4E2D\u5B8C\u6210\u3002\u4F60\u53EF\u4EE5\u901A\u8FC7 Controller \u53D1\u8D77\u6D4B\u8BD5\u3001\u505C\u6B62\u6D4B\u8BD5\u3001\u8C03\u6574\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u7684\u5404\u79CD\u53C2\u6570\uFF0C\u8FD8\u53EF\u4EE5\u76D1\u63A7\u6D4B\u8BD5\u7684\u6267\u884C\u8FC7\u7A0B\u3002</p><p><strong>\u9636\u6BB5 5\uFF1A\u5206\u6790\u6D4B\u8BD5\u62A5\u544A</strong></p><p>\u6267\u884C\u5B8C\u6027\u80FD\u6D4B\u8BD5\u540E\uFF0CLoadRunner \u4F1A\u6839\u636E\u81EA\u5DF1\u7684\u6807\u51C6\u5E76\u7ED3\u5408\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u4E2D\u5B9A\u4E49\u7684\u7CFB\u7EDF\u76D1\u63A7\u5668\u6307\u6807\uFF0C\u751F\u6210\u5B8C\u6574\u7684\u6D4B\u8BD5\u62A5\u544A\u3002\u5728 Analysis \u4E2D\uFF0C\u4E0D\u4EC5\u53EF\u4EE5\u4EE5\u56FE\u5F62\u5316\u7684\u65B9\u5F0F\u663E\u793A\u5355\u4E2A\u6307\u6807\uFF0C\u4E5F\u53EF\u4EE5\u5C06\u591A\u4E2A\u6307\u6807\u5173\u8054\u5728\u4E00\u8D77\u8FDB\u884C\u6BD4\u8F83\u5206\u6790\u3002</p><p>\u56FE 8 \u5C55\u793A\u4E86\u4F7F\u7528 LoadRunner Analysis \u5C55\u793A\u4E8B\u52A1\u5E73\u5747\u54CD\u5E94\u65F6\u95F4\u7684\u754C\u9762\uFF0C\u6211\u4EEC\u53EF\u4EE5\u770B\u5230\u56FE\u7247\u53F3\u4E0B\u89D2\u5404\u4E2A\u4E8B\u52A1\u7684\u6700\u5C0F\u54CD\u5E94\u65F6\u95F4\u3001\u6700\u5927\u54CD\u5E94\u65F6\u95F4\u548C\u5E73\u5747\u54CD\u5E94\u65F6\u95F4\u3002</p><p><img src="https://static001.geekbang.org/resource/image/88/ea/88f90cc95b59e24a5c7b19848433fcea.png" alt="\u6027\u80FD\u6D4B\u8BD5\u62A5\u544A\u7684\u5206\u6790"></p><p>\u6027\u80FD\u6D4B\u8BD5\u62A5\u544A\u7684\u5206\u6790\uFF0C\u662F\u4E00\u9879\u6280\u672F\u542B\u91CF\u975E\u5E38\u9AD8\u7684\u5DE5\u4F5C\u3002\u4F18\u79C0\u7684\u6027\u80FD\u6D4B\u8BD5\u5DE5\u7A0B\uFF0C\u901A\u8FC7\u62A5\u544A\u4E2D\u7684\u6570\u503C\u4EE5\u53CA\u6570\u503C\u4E4B\u95F4\u7684\u76F8\u4E92\u5173\u7CFB\uFF0C\u5C31\u80FD\u5224\u65AD\u51FA\u7CFB\u7EDF\u4E2D\u53EF\u80FD\u5B58\u5728\u7684\u95EE\u9898\u3002\u8FD9\u5C31\u597D\u6BD4\u533B\u751F\u770B\u9A8C\u8840\u62A5\u544A\uFF0C\u7ECF\u9A8C\u4E30\u5BCC\u7684\u533B\u751F\u53EF\u4EE5\u6839\u636E\u9A8C\u8840\u62A5\u544A\u5BF9\u75C5\u60C5\u505A\u51FA\u516B\u4E5D\u4E0D\u79BB\u5341\u7684\u5224\u65AD\u3002</p><p>\u6027\u80FD\u6D4B\u8BD5\u62A5\u544A\u7684\u89E3\u8BFB\uFF0C\u9700\u8981\u4E30\u5BCC\u7684\u7CFB\u7EDF\u67B6\u6784\u3001\u6027\u80FD\u7406\u8BBA\u4EE5\u53CA\u5927\u91CF\u5B9E\u6218\u7ECF\u9A8C\u7684\u79EF\u7D2F\u3002\u8FD9\u4E2A\u8BDD\u9898\u5DF2\u7ECF\u8D85\u51FA\u4E86\u6211\u4ECA\u5929\u8981\u5206\u4EAB\u7684\u8303\u56F4\uFF0C\u6240\u4EE5\u6211\u4E5F\u5C31\u4E0D\u518D\u7EE7\u7EED\u5C55\u5F00\u4E86\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u4ECA\u5929\u63A5\u7740\u4E0A\u4E00\u7BC7\u6587\u7AE0\uFF0C\u6211\u548C\u4F60\u5206\u4EAB\u4E86\u4F01\u4E1A\u7EA7\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u540E\u56DB\u4E2A\u9636\u6BB5\u7684\u5185\u5BB9\uFF0C\u5305\u62EC\u5F55\u5236\u5E76\u589E\u5F3A\u865A\u62DF\u7528\u6237\u811A\u672C\u3001\u521B\u5EFA\u5E76\u5B9A\u4E49\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u3001\u6267\u884C\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\uFF0C\u4EE5\u53CA\u5206\u6790\u6D4B\u8BD5\u62A5\u544A\u3002\u73B0\u5728\uFF0C\u6211\u518D\u4E3A\u4F60\u603B\u7ED3\u4E00\u4E0B\u6BCF\u4E00\u4E2A\u9636\u6BB5\u7684\u91CD\u70B9\u5185\u5BB9\u3002</p><p>\u5F55\u5236\u5E76\u589E\u5F3A\u865A\u62DF\u7528\u6237\u811A\u672C\uFF0C\u8FD9\u4E2A\u9636\u6BB5\u7684\u5DE5\u4F5C\u53C8\u53EF\u4EE5\u5206\u4E3A\u8BC6\u522B\u88AB\u6D4B\u5E94\u7528\u4F7F\u7528\u7684\u534F\u8BAE\u3001\u5F55\u5236\u811A\u672C\u3001\u5B8C\u5584\u5F55\u5236\u5F97\u5230\u7684\u811A\u672C\u3001\u9A8C\u8BC1\u811A\u672C\u7684\u6B63\u786E\u6027\u56DB\u6B65\u3002\u5176\u4E2D\uFF0C\u5B8C\u5584\u5F55\u5236\u5F97\u5230\u7684\u811A\u672C\u8FD9\u4E00\u6B65\uFF0C\u6D89\u53CA\u5230\u4E86\u5F88\u591A\u6982\u5FF5\u548C\u57FA\u7840\u77E5\u8BC6\uFF0C\u6240\u4EE5\u6211\u8FDB\u884C\u4E86\u91CD\u70B9\u8BB2\u89E3\uFF0C\u5E0C\u671B\u5E2E\u4F60\u514B\u670D\u6027\u80FD\u6D4B\u8BD5\u7684\u96BE\u70B9\u3002</p><p>\u521B\u5EFA\u5E76\u5B9A\u4E49\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\uFF0C\u4EE5\u53CA\u6267\u884C\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\uFF0C\u8FD9\u4E24\u4E2A\u9636\u6BB5\u7684\u5DE5\u4F5C\u90FD\u662F\u5728 LoadRunner \u7684 Controller \u6A21\u5757\u4E2D\u5B8C\u6210\u7684\uFF0C\u4E5F\u90FD\u6BD4\u8F83\u7B80\u5355\u3002\u4F60\u53EF\u4EE5\u53C2\u8003\u6211\u5728\u300A\u5DE5\u6B32\u5584\u5176\u4E8B\u5FC5\u5148\u5229\u5176\u5668\uFF1A\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u539F\u7406\u4E0E\u884C\u4E1A\u5E38\u7528\u5DE5\u5177\u7B80\u4ECB\u300B\u8FD9\u7BC7\u6587\u7AE0\u5206\u4EAB\u7684\u5185\u5BB9\uFF0C\u5B8C\u6210\u8FD9\u4E24\u4E2A\u9636\u6BB5\u7684\u5DE5\u4F5C\u3002</p><p>\u5206\u6790\u6D4B\u8BD5\u62A5\u544A\uFF0C\u8FD9\u4E2A\u5DE5\u4F5C\u7684\u6280\u672F\u542B\u91CF\u975E\u5E38\u9AD8\u3002\u6DF1\u5165\u89E3\u8BFB\u6027\u80FD\u6D4B\u8BD5\u62A5\u544A\u7684\u80FD\u529B\uFF0C\u9700\u8981\u4E30\u5BCC\u7684\u7CFB\u7EDF\u67B6\u6784\u3001\u6027\u80FD\u7406\u8BBA\uFF0C\u4EE5\u53CA\u5927\u91CF\u5B9E\u6218\u7ECF\u9A8C\u3002\u6240\u4EE5\uFF0C\u6211\u4EEC\u9700\u8981\u5728\u5E73\u65F6\u5DE5\u4F5C\u4E2D\uFF0C\u4E0D\u65AD\u5730\u4E30\u5BCC\u81EA\u5DF1\u7684\u77E5\u8BC6\u4F53\u7CFB\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u4F60\u4EEC\u516C\u53F8\u7684\u6027\u80FD\u6D4B\u8BD5\u662F\u5426\u4F7F\u7528 LoadRunner\uFF0C\u5728\u4F7F\u7528\u8FC7\u7A0B\u4E2D\u9047\u5230\u4E86\u4EC0\u4E48\u96BE\u9898\uFF1F\u4F60\u4EEC\u53C8\u662F\u5982\u4F55\u89E3\u51B3\u7684\u5462\uFF1F</p>',96);function i(n,o){return t}var l=p(r,[["render",i],["__file","33.html.vue"]]);export{l as default};
